			"events": []any{
				map[string]any{
					"kind":       "execute-bead",
					"summary":    "execution_failed",
					"body":       "execute-loop: all tiers exhausted - no viable provider found",
					"created_at": "2026-01-01T00:00:00Z",
				},
			},
		},
